import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useRef
} from 'react';
import { Connection, clusterApiUrl, Keypair, PublicKey } from '@solana/web3.js';

const AppContext = createContext();

export function AppProvider({ children }) {
  const [network, setNetwork] = useState('devnet');
  const [connection, setConnection] = useState(null);
  const [wallets, setWallets] = useState([]);
  const [balances, setBalances] = useState({});
  const [deployedToken, setDeployedToken] = useState(null);
  const [logs, setLogs] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  const isMounted = useRef(true);

  useEffect(() => {
    return () => {
      isMounted.current = false;
    };
  }, []);

  // Initialize connection
  useEffect(() => {
    try {
      const conn = new Connection(clusterApiUrl(network), 'confirmed');
      setConnection(conn);
      console.log('Connected to', network);
    } catch (err) {
      console.error('Failed to create connection:', err);
    }
  }, [network]);

  const addLog = useCallback((msg, type = 'info') => {
    if (!isMounted.current) return;
    setLogs(prev => [...prev, { 
      msg, 
      type, 
      time: new Date().toLocaleTimeString() 
    }]);
  }, []);

  // FORCE LOAD COMPLETE after 2 seconds - no storage at all
  useEffect(() => {
    console.log('Starting load...');

    const timer = setTimeout(() => {
      if (isMounted.current) {
        console.log('Load complete');
        setIsLoading(false);
        setLogs([{
          msg: 'System ready (no persistence)',
          type: 'warning',
          time: new Date().toLocaleTimeString()
        }]);
      }
    }, 2000);

    return () => clearTimeout(timer);
  }, []);

  const refreshBalances = useCallback(async () => {
    if (!connection || wallets.length === 0) return;

    console.log('Refreshing balances...');
    const newBalances = {};

    for (const w of wallets) {
      try {
        const lamports = await connection.getBalance(new PublicKey(w.publicKey));
        newBalances[w.publicKey] = lamports / 1000000000;
        console.log('Balance for', w.publicKey.slice(0,8), ':', newBalances[w.publicKey]);
      } catch (err) {
        console.error('Balance fetch failed:', err);
        newBalances[w.publicKey] = 0;
      }
    }

    if (isMounted.current) {
      setBalances(newBalances);
    }
  }, [connection, wallets]);

  const addWallet = useCallback(async (name) => {
    try {
      const newKeypair = Keypair.generate();
      const newWallet = {
        name: name || 'Wallet ' + (wallets.length + 1),
        publicKey: newKeypair.publicKey.toString(),
        keypair: newKeypair
      };

      setWallets(prev => [...prev, newWallet]);
      addLog('Created: ' + newWallet.publicKey.slice(0, 8) + '...', 'success');
      return newWallet;
    } catch (err) {
      addLog('Failed to create wallet', 'error');
      return null;
    }
  }, [wallets.length, addLog]);

  const importWallet = useCallback(async (name, secretKey) => {
    try {
      const secretKeyArray = secretKey instanceof Uint8Array
        ? secretKey
        : new Uint8Array(secretKey);

      const keypair = Keypair.fromSecretKey(secretKeyArray);
      const newWallet = {
        name: name || 'Imported ' + (wallets.length + 1),
        publicKey: keypair.publicKey.toString(),
        keypair: keypair
      };

      if (wallets.some(w => w.publicKey === newWallet.publicKey)) {
        addLog('Wallet already exists', 'warning');
        return null;
      }

      setWallets(prev => [...prev, newWallet]);
      addLog('Imported: ' + newWallet.publicKey.slice(0, 8) + '...', 'success');
      return newWallet;
    } catch (err) {
      addLog('Import failed: ' + err.message, 'error');
      return null;
    }
  }, [wallets.length, wallets, addLog]);

  const removeWallet = useCallback((publicKey) => {
    setWallets(prev => prev.filter(w => w.publicKey !== publicKey));
    setBalances(prev => {
      const newBalances = { ...prev };
      delete newBalances[publicKey];
      return newBalances;
    });
    addLog('Wallet removed', 'info');
  }, [addLog]);

  const clearAllData = useCallback(() => {
    setWallets([]);
    setBalances({});
    setDeployedToken(null);
    setLogs([{
      msg: 'All data cleared',
      type: 'info',
      time: new Date().toLocaleTimeString()
    }]);
  }, [addLog]);

  const refreshWalletBalances = useCallback(() => {
    refreshBalances();
    addLog('Balances refreshed', 'info');
  }, [refreshBalances, addLog]);

  if (isLoading) {
    return (
      <div style={{ 
        padding: '20px', 
        textAlign: 'center',
        background: '#0a0a0f',
        color: '#00f3ff',
        minHeight: '100vh',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center'
      }}>
        <h2>Loading Nexus...</h2>
        <p style={{ color: '#666', fontSize: '12px' }}>Please wait...</p>
      </div>
    );
  }

  return (
    <AppContext.Provider value={{
      network,
      setNetwork,
      connection,
      wallets,
      balances,
      setWallets,
      addWallet,
      importWallet,
      removeWallet,
      deployedToken,
      setDeployedToken,
      logs,
      addLog,
      clearAllData,
      refreshWalletBalances
    }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error('useApp must be used within AppProvider');
  }
  return context;
}
